@extends('layouts.app')

@section('content')
@php
    $currentSort = $sort ?? 'id';
    $currentDir = $dir ?? 'desc';
    $toFa = fn ($value) => strtr((string) $value, ['0'=>'۰','1'=>'۱','2'=>'۲','3'=>'۳','4'=>'۴','5'=>'۵','6'=>'۶','7'=>'۷','8'=>'۸','9'=>'۹']);
    $money = fn ($value) => $toFa(\App\Support\Currency::formatRial($value ?? 0));
    $sortLink = function (string $key) use ($currentSort, $currentDir) {
        $nextDir = ($currentSort === $key && $currentDir === 'asc') ? 'desc' : 'asc';
        return route('products.index', array_merge(request()->query(), ['sort' => $key, 'dir' => $nextDir, 'page' => null]));
    };
    $sortArrow = fn (string $key) => $currentSort !== $key ? '↕' : ($currentDir === 'asc' ? '↑' : '↓');
    $user = auth()->user();
    $canDeleteProducts = $user && method_exists($user, 'hasAnyRole') && $user->hasAnyRole(['admin', 'Admin']);
@endphp

