<script>
document.addEventListener('DOMContentLoaded', function(){
    const deleteForm=document.getElementById('bulkDeleteForm');const modalEl=document.getElementById('stockBreakdownModal');const modal=modalEl?new bootstrap.Modal(modalEl):null;const stockTitleEl=document.getElementById('stockBreakdownTitle');const stockNameEl=document.getElementById('stockBreakdownProductName');const stockHeadEl=document.getElementById('stockBreakdownHead');const stockBodyEl=document.getElementById('stockBreakdownBody');
    const faNumber=v=>String(v??'').replace(/\d/g,d=>'۰۱۲۳۴۵۶۷۸۹'[d]);
    const parseJsonDataset=(raw,fallback=[])=>{if(!raw)return fallback;try{return JSON.parse(raw)}catch(e){return fallback}};
    const uniqueByProduct=items=>Array.from(new Map(items.map(ch=>[String(ch.dataset.productId||ch.value),ch])).values());
    function allChecks(){return Array.from(document.querySelectorAll('.product-checkbox'))}
    function selected(){return uniqueByProduct(allChecks().filter(ch=>ch.checked))}
    function syncProductChecks(productId,checked){allChecks().filter(ch=>String(ch.dataset.productId||ch.value)===String(productId)).forEach(ch=>{ch.checked=checked})}
    function single(){const s=selected();if(s.length!==1){alert('برای این عملیات باید دقیقا یک کالا انتخاب شود.');return null}return s[0]}
    function setActionState(count){['bulkEditBtn','bulkSalesLedgerBtn','bulkPurchaseLedgerBtn'].forEach(id=>{const el=document.getElementById(id);if(el)el.disabled=count!==1});const stock=document.getElementById('bulkStockBtn');if(stock)stock.disabled=count!==1;const del=document.getElementById('bulkDeleteBtn');if(del)del.disabled=count<1;const deact=document.getElementById('bulkDeactivateBtn');if(deact)deact.disabled=count<1}
    function productVariants(productId){const source=document.getElementById(`product-variants-${productId}`);return source?parseJsonDataset(source.textContent,[]):[]}
    function fillVariantSelect(item, preferredId=''){const variant=document.getElementById('bulkVariantSelect'),help=document.getElementById('variantHelpText');if(!variant)return;const productId=item.dataset.productId||item.value;const vars=productVariants(productId);variant.innerHTML='';if(!vars.length){variant.innerHTML='<option value="">این کالا تنوعی ندارد</option>';variant.disabled=true;if(help)help.textContent='این کالا تنوع ثبت‌شده‌ای ندارد؛ عملیات روی کل کالا انجام می‌شود.';return}variant.disabled=false;if(vars.length>1){variant.insertAdjacentHTML('beforeend','<option value="">همه تنوع‌ها / بدون انتخاب تنوع</option>')}vars.forEach(v=>{const o=document.createElement('option');o.value=String(v.id);const code=v.code||v.sku||v.barcode||'';o.textContent=`${v.name??'تنوع'}${code?` (${code})`:''} | موجودی مرکزی: ${faNumber(v.central_stock??0)}`;variant.appendChild(o)});variant.value=preferredId&&vars.some(v=>String(v.id)===String(preferredId))?String(preferredId):(vars.length===1?String(vars[0].id):'');if(help)help.textContent='برای کارتکس یا موجودی تفکیکی، تنوع موردنظر را انتخاب کنید.'}
    function updateBulkActionState(preferredVariantId=''){const s=selected(),strip=document.getElementById('operationStrip'),badge=document.getElementById('selectedCountBadge'),title=document.getElementById('selectedProductTitle'),help=document.getElementById('variantHelpText'),variant=document.getElementById('bulkVariantSelect'),deact=document.getElementById('bulkDeactivateBtn');strip?.classList.toggle('has-selection',s.length>0);setActionState(s.length);if(badge)badge.textContent=faNumber(s.length);if(!variant)return;if(!s.length){if(title)title.textContent='هیچ کالایی انتخاب نشده است';if(help)help.textContent='ابتدا یک کالا را انتخاب کنید';variant.innerHTML='<option value="">ابتدا یک کالا را انتخاب کنید</option>';variant.disabled=true;return}if(s.length>1){if(title)title.textContent=faNumber(s.length)+' کالا انتخاب شده است';if(help)help.textContent='انتخاب تنوع فقط برای یک کالا امکان‌پذیر است';variant.innerHTML='<option value="">انتخاب تنوع فقط برای یک کالا امکان‌پذیر است</option>';variant.disabled=true;return}const item=s[0];if(title)title.textContent=(item.dataset.productName||'کالای انتخاب شده')+' انتخاب شده است';if(deact)deact.textContent=item.dataset.isSellable==='1'?'غیرفعال‌سازی':'سوابق غیرفعال‌سازی';fillVariantSelect(item,preferredVariantId)}
    function bindProductSelection(){document.querySelectorAll('.select-all-products').forEach(sel=>{sel.onchange=function(){allChecks().forEach(ch=>syncProductChecks(ch.dataset.productId||ch.value,this.checked));updateBulkActionState()}});allChecks().forEach(ch=>{ch.onchange=function(e){syncProductChecks(this.dataset.productId||this.value,this.checked);updateBulkActionState()}})}
    function bindVariantToggles(){document.querySelectorAll('.variant-toggle').forEach(btn=>{btn.onclick=e=>e.stopPropagation();const target=document.querySelector(btn.getAttribute('data-bs-target'));const symbol=btn.querySelector('.variant-symbol');if(!target||!symbol)return;target.addEventListener('shown.bs.collapse',()=>symbol.textContent='−',{once:false});target.addEventListener('hidden.bs.collapse',()=>symbol.textContent='+',{once:false})})}
    function bindMobileVariantAccordions(){document.querySelectorAll('.mobile-variant-toggle').forEach(btn=>{btn.onclick=e=>e.stopPropagation()})}
    function bindVariantRowSelection(){document.querySelectorAll('.select-variant-btn,.variant-row-selectable').forEach(el=>{el.onclick=function(e){e.preventDefault();e.stopPropagation();const productId=this.dataset.productId,variantId=this.dataset.variantId;if(productId){syncProductChecks(productId,true);updateBulkActionState(variantId)}}})}
    function initProductsPageBindings(){bindProductSelection();bindVariantToggles();bindMobileVariantAccordions();bindVariantRowSelection();bindAjaxChrome();bindBulkActionButtons();updateBulkActionState()}
    function loadProducts(url,pushState=true){const area=document.getElementById('productsAjaxArea');if(!area)return;area.style.opacity='.55';fetch(url,{headers:{'X-Requested-With':'XMLHttpRequest'}}).then(r=>r.text()).then(html=>{const doc=new DOMParser().parseFromString(html,'text/html'),incoming=doc.getElementById('productsAjaxArea');if(!incoming){window.location.href=url;return}area.innerHTML=incoming.innerHTML;if(pushState)history.pushState({},'',url);initProductsPageBindings();const opened=bootstrap.Offcanvas.getInstance(document.getElementById('catOffcanvas'));opened?.hide()}).catch(()=>window.location.href=url).finally(()=>area.style.opacity='1')}
    function bindAjaxChrome(){document.getElementById('filterToggleBtn')?.addEventListener('click',function(){const panel=document.getElementById('productFilterPanel');panel?.classList.toggle('is-open');this.setAttribute('aria-expanded',panel?.classList.contains('is-open')?'true':'false');this.textContent=panel?.classList.contains('is-open')?'بستن جستجو و فیلترها':'نمایش جستجو و فیلترها'});document.getElementById('productFilterForm')?.addEventListener('submit',function(e){e.preventDefault();const fd=new FormData(this);const quick=this.querySelector('.quick-search-mobile');if(quick&&quick.value)fd.set('q',quick.value);loadProducts(`${this.action}?${new URLSearchParams(fd).toString()}`)});document.querySelectorAll('#productsAjaxArea a.sortable-link,#productsAjaxArea .pagination a,#catTreeMobile a').forEach(a=>a.addEventListener('click',function(e){if(!this.href||!this.href.includes('/products'))return;e.preventDefault();loadProducts(this.href)}));document.querySelector('#productsAjaxArea a.btn-outline-secondary[href*="products"]')?.addEventListener('click',function(e){e.preventDefault();loadProducts(this.href)})}
    function bindBulkActionButtons(){const edit=document.getElementById('bulkEditBtn');if(edit)edit.onclick=()=>{const s=single();if(s)location.href=s.dataset.editUrl};const del=document.getElementById('bulkDeleteBtn');if(del)del.onclick=()=>{const items=selected();if(!items.length)return;if(items.length>1){alert('حذف گروهی route جداگانه‌ای در این صفحه ندارد؛ لطفاً برای حذف، یک کالا انتخاب کنید.');return}const s=items[0];if(confirm(`کالای «${s.dataset.productName}» حذف شود؟`)){deleteForm.action=s.dataset.deleteUrl;deleteForm.submit()}};const deact=document.getElementById('bulkDeactivateBtn');if(deact)deact.onclick=()=>{const items=selected();if(!items.length)return;if(items.length>1){if(!confirm(faNumber(items.length)+' کالا برای غیرفعال‌سازی انتخاب شده است. به فرم سند غیرفعال‌سازی برویم؟'))return;const first=items[0];const url=new URL(first.dataset.deactivateUrl, window.location.origin);url.searchParams.delete('product_id');url.searchParams.set('product_ids', items.map(i=>i.value).join(','));location.href=url.toString();return}const s=items[0];location.href=s.dataset.isSellable==='1'?s.dataset.deactivateUrl:s.dataset.deactivationHistoryUrl};const stock=document.getElementById('bulkStockBtn');if(stock)stock.onclick=showStock;const purchase=document.getElementById('bulkPurchaseLedgerBtn');if(purchase)purchase.onclick=()=>goLedger('purchaseLedgerUrl');const sales=document.getElementById('bulkSalesLedgerBtn');if(sales)sales.onclick=()=>goLedger('salesLedgerUrl')}
    function goLedger(key){const s=single(),variant=document.getElementById('bulkVariantSelect');if(!s)return;const url=s.dataset[key];if(!url)return;const id=variant?.value||'';location.href=id?`${url}?variant_id=${encodeURIComponent(id)}`:url}
    async function showStock(){const s=selected(),variant=document.getElementById('bulkVariantSelect');if(!s.length||!modal)return;if(s.length>1){alert('نمایش موجودی تفکیکی فقط برای یک کالا امکان‌پذیر است.');return}const item=s[0],selectedVariantId=variant?.value||'',baseUrl=item.dataset.warehouseStockUrl;if(!baseUrl)return;const url=new URL(baseUrl,window.location.origin);if(selectedVariantId)url.searchParams.set('variant_id',selectedVariantId);stockTitleEl.textContent='موجودی کالا به تفکیک انبار';stockNameEl.textContent='در حال دریافت موجودی...';stockHeadEl.innerHTML='';stockBodyEl.innerHTML='<tr><td class="text-center text-muted">در حال دریافت اطلاعات...</td></tr>';modal.show();try{const response=await fetch(url.toString(),{headers:{'Accept':'application/json','X-Requested-With':'XMLHttpRequest'}});const payload=await response.json().catch(()=>({}));if(!response.ok){throw new Error(payload.message||Object.values(payload.errors||{})[0]?.[0]||'خطا در دریافت موجودی انبار.')}renderStockBreakdown(payload)}catch(error){stockNameEl.textContent='';stockHeadEl.innerHTML='';stockBodyEl.innerHTML=`<tr><td class="text-center text-danger">${error.message||'خطا در دریافت موجودی انبار.'}</td></tr>`}}
    function renderStockBreakdown(payload){const rows=Array.isArray(payload.rows)?payload.rows:[],variantMode=!!payload.is_variant_mode;stockTitleEl.textContent=`موجودی کالا به تفکیک انبار - ${payload.title||'کالای انتخاب‌شده'}`;stockNameEl.textContent=variantMode?'نمایش موجودی همین تنوع در انبارها':'نمایش موجودی همه تنوع‌های این کالا در انبارها';stockHeadEl.innerHTML=variantMode?'<tr><th>انبار</th><th class="text-end">موجودی کل</th><th class="text-end">رزرو در پیش‌فاکتور</th><th class="text-end">موجودی آزاد</th></tr>':'<tr><th>کالا / تنوع</th><th>انبار</th><th class="text-end">موجودی کل</th><th class="text-end">رزرو در پیش‌فاکتور</th><th class="text-end">موجودی آزاد</th></tr>';stockBodyEl.innerHTML='';if(!rows.length){const colspan=variantMode?4:5;stockBodyEl.innerHTML=`<tr><td colspan="${colspan}" class="text-center text-muted">برای کالای انتخاب‌شده در انبارها موجودی ثبت نشده است.</td></tr>`;return}rows.forEach(i=>{const tr=document.createElement('tr'),reserved=Number(i.reserved_quantity||0),warning=!!i.has_over_reserved_warning;const reservedText=reserved>0?`${faNumber(reserved)} عدد در پیش‌فاکتور`:'—';const warningText=warning?'<div class="small text-danger mt-1">رزرو ثبت‌شده از موجودی کل بیشتر است؛ لطفاً بررسی شود.</div>':'';const common=`<td>${i.warehouse_name??'—'}</td><td class="text-end fw-bold">${faNumber(i.total_quantity??0)}</td><td class="text-end ${reserved>0?'text-warning fw-bold':''}">${reservedText}</td><td class="text-end fw-bold ${warning?'text-danger':''}">${faNumber(i.available_quantity??0)}${warningText}</td>`;tr.innerHTML=variantMode?common:`<td>${i.variant_title??'—'}</td>${common}`;stockBodyEl.appendChild(tr)})}
    document.getElementById('catSearchMobile')?.addEventListener('input',function(){const q=this.value.trim().toLowerCase();document.querySelectorAll('#catTreeMobile a').forEach(a=>{const li=a.closest('li');if(li)li.style.display=!q||a.textContent.trim().toLowerCase().includes(q)?'':'none'})});initProductsPageBindings();window.addEventListener('popstate',()=>loadProducts(location.href,false));
});
</script>
@endsection
